use std::ops::{Deref, DerefMut};

struct BoxWrapper<T>(T);

impl<T> BoxWrapper<T> {
    fn new(item: T) -> Self {
        BoxWrapper(item)
    }

    fn get_inner(&self) -> &T {
        &self.0
    }

    fn set_inner(&mut self, item: T) {
        self.0 = item;
    }
}

impl<T> Deref for BoxWrapper<T> where T: std::fmt::Debug {
    type Target = T;

    fn deref(&self) -> &Self::Target {
        &self.0
    }
}

impl<T> DerefMut for BoxWrapper<T> where T: std::fmt::Debug {
    fn deref_mut(&mut self) -> &mut Self::Target {
        &mut self.0
    }
}

impl<T: std::fmt::Debug> std::fmt::Display for BoxWrapper<T> {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{:?}", self.0)
    }
}

fn main() {
    let mut data = BoxWrapper::new(String::from("Initial Text"));
    println!("Read-only access: {}", data);

    let mut mutable_data = BoxWrapper::new(100i32);
    *mutable_data = 50;
    println!("Mutated value: {}", mutable_data);
}

use std::ops::{Deref, DerefMut};

struct DataContainer { 
    data: Vec<i32> 
}

impl DataContainer {
    fn new(data: Vec<i32>) -> Self {
        DataContainer { data }
    }
}

impl Deref for DataContainer {
    type Target = [i32];

    fn deref(&self) -> &Self::Target {
        &self.data
    }
}

impl DerefMut for DataContainer {
    fn deref_mut(&mut self) -> &mut Self::Target {
        &mut self.data
    }
}

fn calculate_sum(container: &DataContainer) -> i32 {
    container.iter().sum()
}

fn main() {
    let mut records = DataContainer::new(vec![10, 5, 8]);
    println!("Initial state sum: {}", calculate_sum(&records));

    records.deref_mut()[1] = 2;

    println!("Updated state sum: {}", calculate_sum(&records));
}

