use std::ops::{Deref, DerefMut};

struct MyWrapper<T> { 
    inner: T
}

impl<T> MyWrapper<T> { 
    fn new(val: T) -> Self {
        MyWrapper { inner: val }
    }
}

impl<T> Deref for MyWrapper<T> where T: std::fmt::Debug {
    type Target = T;

    fn deref(&self) -> &Self::Target {
        &self.inner
    }
}

impl<T> DerefMut for MyWrapper<T> where T: std::fmt::Debug {
    fn deref_mut(&mut self) -> &mut Self::Target {
        &mut self.inner
    }
}

impl<T> std::fmt::Display for MyWrapper<T> where T: std::fmt::Display {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}", self.inner)
    }
}

fn main() {
    let mut wrapper = MyWrapper::new(String::from("Hello World"));

    println!("Original value: {}", wrapper);

    let s_ref: &str = &wrapper;
    println!("Dereferenced as &str: {}", s_ref);

    let mut s_mut: String = wrapper.inner.to_string();
    s_mut.to_uppercase();
    println!("Mutated value: {}", s_mut);
}

use std::fmt::{self, Debug};

trait Printable {
    fn print_value(&self) -> String;
}

struct Container<T: Printable> {
    inner: T,
}

impl<T: Printable> Printable for Container<T> {
    fn print_value(&self) -> String {
        format!("The container holds something printable: {}", self.inner.print_value())
    }
}

struct Widget {
    id: u32,
    name: String,
}

impl Printable for Widget {
    fn print_value(&self) -> String {
        format!("Widget ID {} named {}", self.id, self.name)
    }
}

fn process_printable<P: Printable>(item: &P) -> String {
    item.print_value()
}

fn main() {
    let widget = Widget { id: 101, name: String::from("Settings") };
    println!("Processing standalone widget: {}", process_printable(&widget));

    let box_of_settings = Container { inner: widget };
    println!("Processing wrapped widget: {}", process_printable(&box_of_settings));
}
